#!/usr/bin/env python3
# =============================================================================
# SCRIPT METADATA (Generated by g_code for RQ 6.9.8)
# =============================================================================
"""
Step ID: step03
Step Name: Test Moderation - Mixed-Effects Regression
RQ: results/ch6/6.9.8
Generated: 2026-01-20

PURPOSE:
Test whether schema condition moderates the confidence-accuracy relationship using
mixed-effects regression with random intercepts for participants. If interaction terms
are non-significant (p > 0.05), schema does NOT moderate the relationship.

EXPECTED INPUTS:
- results/ch6/6.9.8/data/step01_reshaped_long.csv (filter to T1/T2/T4 -> 900 rows)
  Columns: UID, test, schema_condition, theta_accuracy, theta_confidence

EXPECTED OUTPUTS:
- results/ch6/6.9.8/data/step03_moderation_test.csv (6 rows: fixed effects table)
  Columns: term, beta, SE, t_value, p_value, CI_lower, CI_upper
- results/ch6/6.9.8/data/step03_moderation_diagnostics.txt (model fit statistics)

VALIDATION CRITERIA:
- Model converged successfully
- 900 observations, 100 groups (UIDs)
- Main effect of confidence_z positive and significant (expected)
- Interaction terms non-significant (p > 0.05, supporting NULL moderation)

g_code REASONING:
- Approach: Mixed-effects model with random intercepts (1|UID), interaction terms test moderation
- Why this approach: Handles non-independence of repeated measures within participants
- Data flow: Load -> filter -> standardize -> create dummies -> fit model -> extract results
- Expected performance: <10 seconds
"""
# =============================================================================

import sys
from pathlib import Path
import pandas as pd
import numpy as np
from scipy.stats import zscore
import statsmodels.formula.api as smf

# =============================================================================
# Configuration
# =============================================================================

RQ_DIR = Path(__file__).resolve().parents[1]  # results/ch6/6.9.8
LOG_FILE = RQ_DIR / "logs" / "step03_moderation_test.log"
INPUT_FILE = RQ_DIR / "data" / "step01_reshaped_long.csv"
OUTPUT_FILE = RQ_DIR / "data" / "step03_moderation_test.csv"
DIAGNOSTICS_FILE = RQ_DIR / "data" / "step03_moderation_diagnostics.txt"

# Key timepoints for analysis
KEY_TIMEPOINTS = ['T1', 'T2', 'T4']

# =============================================================================
# Logging Function
# =============================================================================

def log(msg):
    """Write to both log file and console with flush."""
    with open(LOG_FILE, 'a', encoding='utf-8') as f:
        f.write(f"{msg}\n")
        f.flush()
    print(msg, flush=True)

# =============================================================================
# Main Analysis
# =============================================================================

if __name__ == "__main__":
    try:
        log("[START] Step 03: Test Moderation with Mixed-Effects Model")

        # =====================================================================
        # STEP 1: Load and Prepare Data
        # =====================================================================
        log("[LOAD] Loading long-format data...")
        df = pd.read_csv(INPUT_FILE)
        log(f"[LOADED] {len(df)} rows")

        log("[FILTER] Filtering to key timepoints...")
        df_key = df[df['test'].isin(KEY_TIMEPOINTS)].copy()
        log(f"[FILTERED] {len(df_key)} rows retained")

        # Verify expected row count
        expected_rows = 100 * 3 * 3  # 100 UIDs x 3 timepoints x 3 schema conditions
        if len(df_key) != expected_rows:
            log(f"[WARNING] Expected {expected_rows} rows, got {len(df_key)}")

        # Standardize confidence for interpretability
        log("[PREPARE] Standardizing confidence scores...")
        df_key['confidence_z'] = zscore(df_key['theta_confidence'])
        log(f"[INFO] Standardized confidence: mean = {df_key['confidence_z'].mean():.6f}, SD = {df_key['confidence_z'].std():.6f}")

        # Create dummy variables (Common as reference category)
        log("[PREPARE] Creating dummy variables (Common as reference)...")
        df_key['schema_Congruent'] = (df_key['schema_condition'] == 'Congruent').astype(int)
        df_key['schema_Incongruent'] = (df_key['schema_condition'] == 'Incongruent').astype(int)

        log(f"[INFO] Congruent: {df_key['schema_Congruent'].sum()} rows")
        log(f"[INFO] Incongruent: {df_key['schema_Incongruent'].sum()} rows")
        log(f"[INFO] Common (reference): {(df_key['schema_condition'] == 'Common').sum()} rows")

        # =====================================================================
        # STEP 2: Fit Mixed-Effects Model
        # =====================================================================
        log("[MODEL] Fitting mixed-effects model...")
        log("[INFO] Formula: theta_accuracy ~ confidence_z + schema_Congruent + schema_Incongruent + confidence_z:schema_Congruent + confidence_z:schema_Incongruent")
        log("[INFO] Random effects: random intercepts by UID (1|UID)")

        formula = '''theta_accuracy ~ confidence_z + schema_Congruent + schema_Incongruent +
                     confidence_z:schema_Congruent + confidence_z:schema_Incongruent'''

        model = smf.mixedlm(
            formula=formula,
            data=df_key,
            groups=df_key['UID']
        )

        log("[FITTING] Running optimization (REML method)...")
        result = model.fit(reml=True)  # Restricted Maximum Likelihood
        log("[DONE] Model fitting complete")

        # =====================================================================
        # STEP 3: Extract Results
        # =====================================================================
        log("[EXTRACT] Extracting fixed effects table...")

        # Fixed effects
        fe_results = pd.DataFrame({
            'term': result.params.index.tolist(),
            'beta': result.params.values,
            'SE': result.bse.values,
            't_value': result.tvalues.values,
            'p_value': result.pvalues.values,
            'CI_lower': result.conf_int()[0].values,
            'CI_upper': result.conf_int()[1].values
        })

        log(f"[INFO] Fixed effects: {len(fe_results)} terms")
        for _, row in fe_results.iterrows():
            log(f"  {row['term']:30s}: beta = {row['beta']:7.4f}, SE = {row['SE']:.4f}, t = {row['t_value']:6.2f}, p = {row['p_value']:.4f}")

        # Model diagnostics
        log("[EXTRACT] Extracting model diagnostics...")
        diagnostics = []
        diagnostics.append("=" * 80)
        diagnostics.append("MIXED-EFFECTS MODEL DIAGNOSTICS")
        diagnostics.append("=" * 80)
        diagnostics.append("")
        # Get number of groups from model object (not result)
        n_groups = len(df_key['UID'].unique())

        diagnostics.append(f"Converged: {result.converged}")
        diagnostics.append(f"Observations: {result.nobs}")
        diagnostics.append(f"Groups (UIDs): {n_groups}")
        diagnostics.append(f"AIC: {result.aic:.2f}")
        diagnostics.append(f"BIC: {result.bic:.2f}")
        diagnostics.append(f"Log-Likelihood: {result.llf:.2f}")
        diagnostics.append("")
        diagnostics.append("Random Effects Variance:")
        diagnostics.append(f"  Group (UID): {result.cov_re.values[0, 0]:.4f}")
        diagnostics.append(f"  Residual: {result.scale:.4f}")
        diagnostics.append("")
        diagnostics.append("Fixed Effects Summary:")
        diagnostics.append(str(result.summary().tables[1]))
        diagnostics.append("")
        diagnostics.append("=" * 80)

        log(f"[INFO] Model converged: {result.converged}")
        log(f"[INFO] Observations: {result.nobs}, Groups: {n_groups}")
        log(f"[INFO] AIC = {result.aic:.2f}, BIC = {result.bic:.2f}")

        # =====================================================================
        # STEP 4: Validate Results
        # =====================================================================
        log("[VALIDATION] Checking model results...")

        errors = []

        # Check convergence
        if not result.converged:
            errors.append("Model did not converge")
        else:
            log("[PASS] Model converged successfully")

        # Check expected row count (may include Group Var from random effects)
        if len(fe_results) < 6:
            errors.append(f"Expected at least 6 fixed effects terms, got {len(fe_results)}")
        elif len(fe_results) == 6:
            log("[PASS] Fixed effects: 6 terms (Intercept + 5 predictors)")
        else:
            log(f"[INFO] Fixed effects table has {len(fe_results)} rows (includes Group Var)")

        # Check observations and groups
        if result.nobs != 900:
            log(f"[WARNING] Expected 900 observations, got {result.nobs}")
        else:
            log("[PASS] Observations: 900")

        if n_groups != 100:
            log(f"[WARNING] Expected 100 groups (UIDs), got {n_groups}")
        else:
            log("[PASS] Groups: 100 (UIDs)")

        # Check SE values positive
        if (fe_results['SE'] <= 0).any():
            errors.append("Found non-positive SE values")
        else:
            log("[PASS] All SE values positive")

        # Check main effect of confidence_z
        conf_main = fe_results[fe_results['term'] == 'confidence_z']
        if not conf_main.empty:
            if conf_main['beta'].values[0] > 0 and conf_main['p_value'].values[0] < 0.05:
                log("[PASS] Main effect of confidence_z positive and significant (expected)")
            else:
                log(f"[WARNING] Main effect of confidence_z: beta = {conf_main['beta'].values[0]:.4f}, p = {conf_main['p_value'].values[0]:.4f}")
        else:
            errors.append("confidence_z term not found in results")

        # Check interaction terms
        interaction_terms = fe_results[fe_results['term'].str.contains(':', regex=False)]
        if len(interaction_terms) == 2:
            log(f"[INFO] Interaction terms: {len(interaction_terms)}")
            for _, row in interaction_terms.iterrows():
                if row['p_value'] > 0.05:
                    log(f"[PASS] {row['term']}: p = {row['p_value']:.4f} > 0.05 (non-significant, supports NULL moderation)")
                else:
                    log(f"[WARNING] {row['term']}: p = {row['p_value']:.4f} < 0.05 (significant, contradicts NULL hypothesis)")

            if (interaction_terms['p_value'] > 0.05).all():
                log("[INFO] All interaction terms non-significant -> Schema does NOT moderate relationship")
            else:
                log("[INFO] Some interaction terms significant -> Schema MAY moderate relationship")
        else:
            errors.append(f"Expected 2 interaction terms, found {len(interaction_terms)}")

        # =====================================================================
        # STEP 5: Save Outputs
        # =====================================================================
        if errors:
            log("[VALIDATION] FAIL - Errors detected:")
            for error in errors:
                log(f"  - {error}")
            raise ValueError(f"Validation failed with {len(errors)} error(s)")

        log("[VALIDATION] PASS - All checks passed")

        fe_results.to_csv(OUTPUT_FILE, index=False, encoding='utf-8')
        log(f"[SAVED] Fixed effects table: {OUTPUT_FILE}")

        with open(DIAGNOSTICS_FILE, 'w', encoding='utf-8') as f:
            f.write("\n".join(diagnostics))
        log(f"[SAVED] Model diagnostics: {DIAGNOSTICS_FILE}")

        log("[SUCCESS] Step 03 complete")
        sys.exit(0)

    except Exception as e:
        log(f"[ERROR] {str(e)}")
        import traceback
        log("[TRACEBACK] Full error details:")
        with open(LOG_FILE, 'a', encoding='utf-8') as f:
            traceback.print_exc(file=f)
        traceback.print_exc()
        sys.exit(1)
